import{_ as a,o as e,c as i,d as n}from"./index.4ce7143c.js";const s={},r={class:"adp","data-respond-to-offset":"true"},t=n('<section class="breadcrumbs"><div class="breadcrumbs-overlay"></div><div class="breadcrumbs-wrapper"><div class="breadcrumb-items"><a href="/web/" class="breadcrumb">Rumah</a> <span class="divider"></span> <a href="/web/coffee" class="breadcrumb">Semua Kopi</a> <span class="divider"></span> <a href="/web/coffee/learn" class="breadcrumb">Belajar</a></div></div></section><div class="pimcore_area_advanced-section pimcore_area_content"><div class="brick-wrapper"><div class="container"><div class="row"><div class="col-12"><div class="pimcore_area_advanced-banner-display pimcore_area_content"><div class="brick-wrapper"><div class="banner-display-block m-height-80 t-height-35 d-height-30"><div class="item bg-none" data-arrow-color=""><div class="images"><picture class="lazy"><source media="(min-width:1700px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/5255/image-thumb__5255__responsive_1700_JPEG/articlehero-desktop-35percent-3840x1344.44bf9810.jpg 1x, https://www.folgerscoffee.com/folgers/articles/5255/image-thumb__5255__responsive_3400_JPEG/articlehero-desktop-35percent-3840x1344.59a1580f.jpg 2x" data-alt="articlehero desktop 35percent 3840x1344"><source media="(min-width:1400px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/5255/image-thumb__5255__responsive_1699_JPEG/articlehero-desktop-35percent-3840x1344.965dbc25.jpg 1x, https://www.folgerscoffee.com/folgers/articles/5255/image-thumb__5255__responsive_3398_JPEG/articlehero-desktop-35percent-3840x1344.c42d2dc5.jpg 2x" data-alt="articlehero desktop 35percent 3840x1344"><source media="(min-width:1200px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/5255/image-thumb__5255__responsive_1399_JPEG/articlehero-desktop-35percent-3840x1344.a948078e.jpg 1x, https://www.folgerscoffee.com/folgers/articles/5255/image-thumb__5255__responsive_2798_JPEG/articlehero-desktop-35percent-3840x1344.e72d9e8b.jpg 2x" data-alt="articlehero desktop 35percent 3840x1344"><source media="(min-width:992px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/5255/image-thumb__5255__responsive_1199_JPEG/articlehero-desktop-35percent-3840x1344.86112923.jpg 1x, https://www.folgerscoffee.com/folgers/articles/5255/image-thumb__5255__responsive_2398_JPEG/articlehero-desktop-35percent-3840x1344.0c37a5e6.jpg 2x" data-alt="articlehero desktop 35percent 3840x1344"><source media="(min-width:768px)" type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/5254/image-thumb__5254__responsive_991_JPEG/articlehero-tablet-40percent-1982x793.916341f5.jpg 1x, https://www.folgerscoffee.com/folgers/articles/5254/image-thumb__5254__responsive_1982_JPEG/articlehero-tablet-40percent-1982x793.d5256528.jpg 2x" data-alt="articlehero tablet 40percent 1982x793"><source type="image/jpg" srcset="https://www.folgerscoffee.com/folgers/articles/5253/image-thumb__5253__responsive_767_JPEG/articlehero-mobile-90percent-1534x1381.308c30f7.jpg 1x, https://www.folgerscoffee.com/folgers/articles/5253/image-thumb__5253__responsive_1534_JPEG/articlehero-mobile-90percent-1534x1381.b580fa35.jpg 2x" data-alt="articlehero mobile 90percent 1534x1381"><img alt="articlehero desktop 35percent 3840x1344" class="optanon-category-C0002-C0004-C0005 lazyload" data-src="https://www.folgerscoffee.comhttps://www.folgerscoffee.com/folgers/articles/5253/image-thumb__5253__responsive_1_JPEG/articlehero-mobile-90percent-1534x1381.5e519743.jpg" srcset="https://www.folgerscoffee.com/folgers/articles/5255/image-thumb__5255__responsive_1199_JPEG/articlehero-desktop-35percent-3840x1344.86112923.jpg 1x, https://www.folgerscoffee.com/folgers/articles/5255/image-thumb__5255__responsive_2398_JPEG/articlehero-desktop-35percent-3840x1344.0c37a5e6.jpg 2x"></picture></div></div></div></div></div></div></div></div></div></div><section class="article"><div class="section-inner"><div class="article-wrapper"><div class="article-body"><div class="article-overview-wrapper object-overview-wrapper"><div class="article-information object-information"><div class="article-name"><h1 class="heading">Cara Menyimpan Kopi Ground</h1></div><div class="article-author"><div class="eyebrow"> Oleh: Folgers (Folgerscoffee.com)</div></div><div class="article-description"></div></div></div><div class="pimcore_area_advanced-section pimcore_area_content"><div class="brick-wrapper"><div class="container-full"><div class="row"><div class="col"><div class="pimcore_area_advanced-column pimcore_area_content"><div class="brick-wrapper"><div class="pimcore_area_basic-wysiwyg pimcore_area_content"><div class="brick-wrapper"><div class="align-left"><p>Menyimpan kopi dengan benar adalah kunci untuk menjaga rasa dan aroma yang Anda sukai. Tips dan garis waktu kami akan membantu Anda menjaga kopi <strong>Folgers</strong><sup>\xAE</sup> segar untuk kenikmatan maksimal di setiap cangkir.</p></div></div></div></div></div></div></div></div></div></div><div class="pimcore_area_advanced-section pimcore_area_content"><div class="brick-wrapper"><div class="container-full"><div class="row"><div class="col"><div class="pimcore_area_advanced-column pimcore_area_content"><div class="brick-wrapper"><div class="pimcore_area_basic-input pimcore_area_content"><div class="brick-wrapper"><h2 class="align-left heading"> Faktor-faktor yang mempengaruhi kesegaran kopi</h2></div></div><div class="pimcore_area_basic-wysiwyg pimcore_area_content"><div class="brick-wrapper"><div class="align-left"><p>Seperti menyedihkan untuk mengakui, kopi memang memiliki tanggal kadaluwarsa. Ada juga faktor tertentu yang dapat mempengaruhi kesegaran kopi sebelum tanggal itu tiba. Lakukan yang terbaik untuk menghindari hal-hal ini saat menyimpan kopi untuk mempertahankan rasa dan aroma yang luar biasa itu selama mungkin.\xA0</p></div></div></div><div class="pimcore_area_advanced-section pimcore_area_content"><div class="brick-wrapper"><div class="container-full"><div class="row"><div class="col-12 col-md-6 col-lg-6"><div class="pimcore_area_advanced-column pimcore_area_content"><div class="brick-wrapper"><div class="pimcore_area_basic-wysiwyg pimcore_area_content"><div class="brick-wrapper"><div class="align-left"><p><strong>Oksigen</strong><br>Memaparkan kopi ke udara membuatnya lebih mungkin menjadi usang dan kehilangan rasa.</p><p><strong>Lembah</strong><br>Kopi yang terkena kelembaban dapat merusak dan mengembangkan rasa yang berbentuk jamur dan tidak menyenangkan. </p></div></div></div></div></div></div><div class="col-12 col-md-6 col-lg-6"><div class="pimcore_area_advanced-column pimcore_area_content"><div class="brick-wrapper"><div class="pimcore_area_basic-wysiwyg pimcore_area_content"><div class="brick-wrapper"><div class="align-left"><p><strong>Panas</strong><br>Biji kopi dan tanah dapat dengan mudah menyerap panas, yang menyebabkan mereka kehilangan rasa mereka. </p><p><strong>Cahaya</strong><br>Paparan sinar matahari (dan bahkan cahaya buatan) dapat mempengaruhi kesegaran, meninggalkan kopi Anda dengan rasa lembut atau kuno. </p></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div><div class="pimcore_area_advanced-section pimcore_area_content"><div class="brick-wrapper"><div class="container-full"><div class="row"><div class="col-12 col-md-12 col-lg-12"><div class="pimcore_area_advanced-column pimcore_area_content"><div class="brick-wrapper"><div class="pimcore_area_basic-input pimcore_area_content"><div class="brick-wrapper"><h2 class="align-left heading"> Praktik Terbaik Penyimpanan Kopi</h2></div></div><div class="pimcore_area_basic-input pimcore_area_content"><div class="brick-wrapper"><h4 class="align-left color-dark-red heading">Mengetahui cara menjaga kopi segar berarti memahami cara yang tepat untuk menyimpannya. Gunakan tips ini untuk menyimpan kopi sehingga tetap enak hingga sendok terakhir.</h4></div></div><div class="pimcore_area_advanced-column pimcore_area_content"><div class="brick-wrapper"><div class="pimcore_area_basic-wysiwyg pimcore_area_content"><div class="brick-wrapper"><div class="align-left"><p><strong>Gunakan wadah kedap udara</strong><br>Paparan udara adalah salah satu musuh terbesar kesegaran kopi, jadi memilih wadah kedap udara selalu langkah pertama. Tip pro: pilih wadah dengan katup satu arah yang membiarkan keluar karbon dioksida yang terperangkap sambil mencegah oksigen masuk.</p><p><strong>Simpan di tempat yang dingin dan gelap</strong><br>Karena panas dan cahaya juga harus dihindari, pilih tempat yang dingin dan gelap untuk menyimpan wadah kopi kedap udara Anda. Sebuah pantry atau lemari jauh dari sinar matahari langsung dan sumber panas, seperti oven atau kompor, harus melakukan trik.\xA0</p><p><strong>Jangan kulkas</strong><br>Berbeda dengan kepercayaan populer, menyimpan kopi di kulkas sebenarnya dapat merugikan kopi potongan Anda dengan mengekspos kelembaban dan bau dari makanan lainnya.</p></div></div></div><div class="pimcore_area_basic-image pimcore_area_content"><div class="brick-wrapper"><div class="basic-image m-max-100 t-max-100 d-max-100 m-image-center t-image-center d-image-center"><picture class="lazy"><source media="(min-width:1700px)" type="image/jpeg" srcset="https://www.folgerscoffee.com/folgers/articles/Store%20Ground%20Coffee/5864/image-thumb__5864__responsive_1700_JPEG/Body-1-tablet-desktop.1ee78b87.jpg 1x, https://www.folgerscoffee.com/folgers/articles/Store%20Ground%20Coffee/5864/image-thumb__5864__responsive_3400_JPEG/Body-1-tablet-desktop.604886e8.jpg 2x" data-alt="Body 1 tablet desktop"><source media="(min-width:1400px)" type="image/jpeg" srcset="https://www.folgerscoffee.com/folgers/articles/Store%20Ground%20Coffee/5864/image-thumb__5864__responsive_1699_JPEG/Body-1-tablet-desktop.bd3489f5.jpg 1x, https://www.folgerscoffee.com/folgers/articles/Store%20Ground%20Coffee/5864/image-thumb__5864__responsive_3398_JPEG/Body-1-tablet-desktop.8fd1cae0.jpg 2x" data-alt="Body 1 tablet desktop"><source media="(min-width:1200px)" type="image/jpeg" srcset="https://www.folgerscoffee.com/folgers/articles/Store%20Ground%20Coffee/5864/image-thumb__5864__responsive_1399_JPEG/Body-1-tablet-desktop.74c61738.jpg 1x, https://www.folgerscoffee.com/folgers/articles/Store%20Ground%20Coffee/5864/image-thumb__5864__responsive_2798_JPEG/Body-1-tablet-desktop.f99e1dc7.jpg 2x" data-alt="Body 1 tablet desktop"><source media="(min-width:992px)" type="image/jpeg" srcset="https://www.folgerscoffee.com/folgers/articles/Store%20Ground%20Coffee/5864/image-thumb__5864__responsive_1199_JPEG/Body-1-tablet-desktop.56d98d91.jpg 1x, https://www.folgerscoffee.com/folgers/articles/Store%20Ground%20Coffee/5864/image-thumb__5864__responsive_2398_JPEG/Body-1-tablet-desktop.2eefd794.jpg 2x" data-alt="Body 1 tablet desktop"><source media="(min-width:768px)" type="image/jpeg" srcset="https://www.folgerscoffee.com/folgers/articles/Store%20Ground%20Coffee/5864/image-thumb__5864__responsive_991_JPEG/Body-1-tablet-desktop.ac42ed45.jpg 1x, https://www.folgerscoffee.com/folgers/articles/Store%20Ground%20Coffee/5864/image-thumb__5864__responsive_1982_JPEG/Body-1-tablet-desktop.169a74f2.jpg 2x" data-alt="Body 1 tablet desktop"><source type="image/jpeg" srcset="https://www.folgerscoffee.com/folgers/articles/Store%20Ground%20Coffee/5410/image-thumb__5410__responsive_767_JPEG/Body-1-mobile.5283d53e.jpg 1x, https://www.folgerscoffee.com/folgers/articles/Store%20Ground%20Coffee/5410/image-thumb__5410__responsive_1534_JPEG/Body-1-mobile.88b76137.jpg 2x" data-alt="Body 1 mobile"><img alt="Body 1 tablet desktop" class="optanon-category-C0002-C0004-C0005 lazyload" data-src="https://www.folgerscoffee.comhttps://www.folgerscoffee.com/folgers/articles/Store%20Ground%20Coffee/5410/image-thumb__5410__responsive_1_JPEG/Body-1-mobile.f5bb746e.jpg" srcset="https://www.folgerscoffee.com/folgers/articles/Store%20Ground%20Coffee/5864/image-thumb__5864__responsive_1199_JPEG/Body-1-tablet-desktop.56d98d91.jpg 1x, https://www.folgerscoffee.com/folgers/articles/Store%20Ground%20Coffee/5864/image-thumb__5864__responsive_2398_JPEG/Body-1-tablet-desktop.2eefd794.jpg 2x"></picture></div></div></div><div class="pimcore_area_basic-wysiwyg pimcore_area_content"><div class="brick-wrapper"><div class="align-left"><p><strong>Ketahui tanggal kadaluarsa</strong><br>Kemasan kopi selalu mencakup tanggal kadaluwarsa dan tanggal panggang. Ingatlah tanggal ini dan gunakan kopi Anda sebelum waktu berakhir. Kopi minyak biasanya paling segar dalam dua minggu setelah dipanggang, sementara kopi biji utuh dapat bertahan lebih lama - hingga 4-6 minggu setelah dipanggang.</p><p><strong>Tunggu untuk menggiling</strong><br>Ini untuk semua pecinta kopi biji kami. Alih-alih membeli biji kopi dan menggiling semuanya sekaligus, cobalah menggiling jumlah yang Anda inginkan tepat sebelum membuat bir. Ini akan membantu menjaga rasa dan kesegaran kopi Anda.</p></div></div></div><div class="pimcore_area_basic-input pimcore_area_content"><div class="brick-wrapper"><p class="align-left heading">Jika Anda orang yang suka membeli secara massal, bahkan lebih penting untuk belajar bagaimana menyimpan kopi dengan benar. Kopi paling segar ketika baru panggang, jadi membeli secara massal dapat berarti Anda menyimpan kopi yang sudah kehilangan beberapa rasa segarnya. Tapi, hey, pembelian massal bisa lebih ekonomis. Untuk mengurangi paparan udara, simpan kopi Anda di beberapa wadah kecil yang Anda gunakan satu per satu. Perhatikan juga garis waktu shelf life kopi ini.</p></div></div><div class="pimcore_area_advanced-column pimcore_area_content"><div class="brick-wrapper"><div class="pimcore_area_advanced-table pimcore_area_content"><div class="brick-wrapper"><div class="table styled"><div class="table-row thead"><div class="row-cell" data-thead=""><div class="cell-content"></div></div><div class="row-cell" data-thead="Unopened"><div class="cell-content"><p><strong>Tidak dibuka</strong></p></div></div><div class="row-cell" data-thead="Opened"><div class="cell-content"><p><strong>Dibuka</strong></p></div></div></div><div class="table-row"><div class="row-cell" data-thead=""><div class="cell-content"><p><a href="/web/coffee/ground"><strong>Folgers</strong> Kopi Tanah</a></p></div></div><div class="row-cell" data-thead="Unopened"><div class="cell-content"><p> Perhatikan tanggal \u201Cbest-by\u201D</p></div></div><div class="row-cell" data-thead="Opened"><div class="cell-content"><p>1-3 minggu</p></div></div></div><div class="table-row"><div class="row-cell" data-thead=""><div class="cell-content"><p><a href="/web/coffee/instant"><strong>Folgers</strong> Kopi Instan</a></p></div></div><div class="row-cell" data-thead="Unopened"><div class="cell-content"><p> Perhatikan tanggal \u201Cbest-by\u201D</p></div></div><div class="row-cell" data-thead="Opened"><div class="cell-content"><p>Hingga 1 bulan</p></div></div></div><div class="table-row"><div class="row-cell" data-thead=""><div class="cell-content"><p><a href="/web/coffee/single-serve"><strong>Folgers</strong> Paket Layanan Tunggal</a></p></div></div><div class="row-cell" data-thead="Unopened"><div class="cell-content"><p> Perhatikan tanggal \u201Cbest-by\u201D</p></div></div><div class="row-cell" data-thead="Opened"><div class="cell-content"><p>Hingga 1 tahun</p></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div><div class="pimcore_area_advanced-section pimcore_area_content"><div class="brick-wrapper"><div class="container-full"><div class="row"><div class="col"><div class="pimcore_area_advanced-column pimcore_area_content"><div class="brick-wrapper"><div class="pimcore_area_basic-input pimcore_area_content"><div class="brick-wrapper"><h2 class="align-left heading"> Pertanyaan yang Sering Ditanyakan</h2></div></div><div class="pimcore_area_basic-wysiwyg pimcore_area_content"><div class="brick-wrapper"><div class="align-left"><p><strong>Berapa lama saya bisa menyimpan kopi minyak?</strong><br>Kopi segar dalam dua minggu setelah dipanggang. Menyimpannya di wadah kedap udara di tempat yang dingin dan gelap dapat memperpanjang umur simpannya beberapa minggu lagi. Pertimbangkan untuk membeli kopi dalam batch kecil dan menggunakannya dalam beberapa minggu untuk kesegaran optimal.</p><p><strong>Bisakah kopi berakhir?</strong><br>Setelah tanggal &quot;terbaik&quot; produk, kami tidak dapat menjamin rasa, kualitas dan kinerja yang sama. Menggunakan kopi yang belum dibuka sebelum tanggal &quot;terbaik oleh&quot; (atau kopi terbuka sesuai dengan informasi &quot;penggunaan oleh&quot; pada kemasan) akan membantu memastikan Anda memiliki pengalaman kopi segar mungkin.</p><p><strong>Bagaimana saya bisa tahu apakah kopi minyak saya telah rusak?</strong><br>Jika kopi minyak Anda telah rusak, mungkin memiliki bau kuno atau berambut dan rasa mungkin membosankan atau pahit. Jika kopi minyak Anda tidak bau atau rasanya benar, letakkannya.</p><p><strong>Haruskah saya menyimpan biji kopi utuh atau kopi minyak?</strong><br>Biji kopi utuh umumnya dianggap lebih tahan. Mereka dapat bertahan lebih lama dibandingkan dengan kopi potong (4-6 minggu vs 1-3 minggu setelah dipanggang). Tidak peduli apa yang Anda sukai, penyimpanan yang tepat akan membantu menjaga kopi Anda segar.</p><p><strong>Bisakah saya membekukan kopi?</strong>\xA0<br>Kopi yang dibekukan dapat menyebabkan kelembaban berkembang, yang dapat mempengaruhi rasa secara negatif. Seperti penyimpanan kulkas, penyimpanan freezer juga menjalankan risiko kopi Anda menyerap bau dari makanan lain yang disimpan di sana. Jika Anda ingin membekukan kopi Anda untuk penyimpanan jangka panjang, pastikan untuk menggunakan wadah kedap udara. Anda juga harus berencana untuk menggunakan kopi Anda dalam beberapa minggu setelah pembekuan.</p><p><strong>Bagaimana cara menyimpan kopi instan?</strong>\xA0<br>Seperti kopi minyak, kopi instan harus disimpan dalam wadah kedap udara di tempat yang dingin dan kering. Jauhkan dari kelembaban dan kelembaban juga, karena paparan dapat menyebabkan kopi instan berkumpul atau kehilangan rasa.</p><p><strong>Berapa lama kopi Ground bertahan?</strong><br>Jika disimpan disegel, dingin dan kering, kopi minyak <strong>Folgers</strong> akan tetap segar sampai tanggal &quot;terbaik&quot; dicetak pada kemasan. Kopi minyak kami biasanya dapat dinikmati selama 1-3 minggu setelah dibuka.</p><p><strong>Apa wadah terbaik untuk menyimpan kopi?</strong><br>Sebuah wadah kedap udara adalah yang terbaik - sesuatu yang akan menjaga oksigen dan kelembaban keluar. Kaca dan keramik kontainer adalah pilihan yang bagus karena mereka tidak reaktif dan tidak akan mempengaruhi rasa kopi. Kontainer stainless steel juga bekerja dengan baik karena tahan lama dan masih dapat melindungi kopi dari udara dan kelembaban. Anda juga harus memilih wadah yang ukuran yang tepat untuk jumlah kopi yang Anda simpan - apa pun yang terlalu besar akan memungkinkan kelebihan udara untuk nongkrong, yang dapat mempengaruhi rasa kopi Anda.</p><p><strong>Bisakah kau menyegel kopi?</strong><br>Ya, penyegelan vakum adalah pilihan yang bagus. Ini menghilangkan kelebihan udara dari tas penyimpanan atau wadah Anda, yang dapat membantu menjaga kesegaran kopi Anda lebih lama. Hal ini sangat berguna jika Anda membeli secara massal.</p><p><strong>Bagaimana cara menyimpan kopi dalam jangka panjang?</strong><br>Penyimpanan kopi minyak jangka panjang rumit. Anda dapat membekukan kopi Anda dalam wadah kedap udara atau tas yang disegel vakum. Ketika Anda siap menggunakannya, biarkan sampai suhu kamar sebelum dibuka untuk menghindari membiarkan kelembaban masuk. Anda juga dapat menempatkan penyerap oksigen di wadah kedap udara. Seperti biasa, simpan di tempat yang dingin dan gelap. Tetapi, tidak peduli metode mana yang Anda gunakan dan seberapa baik Anda menyimpannya, ingatlah bahwa kopi akhirnya akan kehilangan rasa dan aromanya. Jangan menunggu terlalu lama untuk menikmatinya.<br>\xA0</p></div></div></div></div></div></div></div></div></div></div></div></div></div></section>',3),d=[t];function o(p,c){return e(),i("main",r,d)}var g=a(s,[["render",o]]);export{g as default};
